    18→
    19→/// Pace state values
    20→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
    21→#[serde(rename_all = "lowercase")]
    22→pub enum jjrg_PaceState {
    23→    Rough,
    24→    Primed,
    25→    Complete,
    26→    Abandoned,
    27→}
    28→
    29→/// Heat status values
    30→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
    31→#[serde(rename_all = "lowercase")]
    32→pub enum jjrg_HeatStatus {
    33→    Current,
    34→    Retired,
    35→}
    36→
    37→/// Tack record - snapshot of Pace state and plan
    38→#[derive(Debug, Clone, Serialize, Deserialize)]
    39→pub struct jjrg_Tack {
    40→    pub ts: String,
    41→    pub state: jjrg_PaceState,
    42→    pub text: String,
    43→    #[serde(skip_serializing_if = "Option::is_none")]
    44→    pub direction: Option<String>,
    45→}
    46→
    47→/// Pace record - discrete action within a Heat
    48→#[derive(Debug, Clone, Serialize, Deserialize)]
    49→pub struct jjrg_Pace {
    50→    pub silks: String,
    51→    pub tacks: Vec<jjrg_Tack>,
    52→}
    53→
    54→/// Heat record - bounded initiative
    55→#[derive(Debug, Clone, Serialize, Deserialize)]
    56→pub struct jjrg_Heat {
    57→    pub silks: String,
    58→    pub creation_time: String,
    59→    pub status: jjrg_HeatStatus,
    60→    pub order: Vec<String>,
    61→    pub next_pace_seed: String,
    62→    pub paddock_file: String,
    63→    pub paces: BTreeMap<String, jjrg_Pace>,
    64→}
    65→
    66→/// Root Gallops structure
    67→#[derive(Debug, Clone, Serialize, Deserialize)]
    68→pub struct jjrg_Gallops {
    69→    pub next_heat_seed: String,
    70→    pub heats: BTreeMap<String, jjrg_Heat>,
    71→}
    72→
    73→// Validation helper functions
    74→
    75→/// Check if string contains only URL-safe base64 characters
    76→pub(crate) fn zjjrg_is_base64(s: &str) -> bool {
    77→    s.bytes().all(|b| JJRF_CHARSET.contains(&b))
    78→}
    79→
    80→/// Check if string is valid kebab-case (non-empty, lowercase alphanumeric with hyphens)
    81→pub(crate) fn zjjrg_is_kebab_case(s: &str) -> bool {
    82→    if s.is_empty() {
    83→        return false;
    84→    }
    85→    // Pattern: [a-z0-9]+(-[a-z0-9]+)*
    86→    let parts: Vec<&str> = s.split('-').collect();
    87→    for part in parts {
    88→        if part.is_empty() {
    89→            return false;
    90→        }
    91→        if !part.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit()) {
    92→            return false;
    93→        }
    94→    }
    95→    true
    96→}
    97→
    98→/// Check if string matches YYMMDD format
    99→pub(crate) fn zjjrg_is_yymmdd(s: &str) -> bool {
   100→    if s.len() != 6 {
   101→        return false;
   102→    }
   103→    s.chars().all(|c| c.is_ascii_digit())
   104→}
   105→
   106→/// Check if string matches YYMMDD-HHMM format
   107→pub(crate) fn zjjrg_is_yymmdd_hhmm(s: &str) -> bool {
   108→    if s.len() != 11 {
   109→        return false;
   110→    }
   111→    let parts: Vec<&str> = s.split('-').collect();
   112→    if parts.len() != 2 {
   113→        return false;
   114→    }
   115→    parts[0].len() == 6
   116→        && parts[0].chars().all(|c| c.is_ascii_digit())
   117→        && parts[1].len() == 4
   118→        && parts[1].chars().all(|c| c.is_ascii_digit())
   119→}
   120→
   121→impl jjrg_Gallops {
   122→    /// Load Gallops from a file path
   123→    pub fn jjrg_load(path: &Path) -> Result<Self, String> {
   124→        let content = fs::read_to_string(path)
   125→            .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
   126→
   127→        let gallops: jjrg_Gallops = serde_json::from_str(&content)
   128→            .map_err(|e| format!("Failed to parse JSON: {}", e))?;
   129→
   130→        Ok(gallops)
   131→    }
   132→
   133→    /// Save Gallops to a file path (atomic write)
   134→    pub fn jjrg_save(&self, path: &Path) -> Result<(), String> {
   135→        // Serialize to pretty JSON
   136→        let content = serde_json::to_string_pretty(self)
   137→            .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
   138→
   139→        // Create temp file in same directory for atomic rename
   140→        let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
   141→        let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
   142→
   143→        // Write to temp file
   144→        let mut file = fs::File::create(&temp_path)
   145→            .map_err(|e| format!("Failed to create temp file: {}", e))?;
   146→        file.write_all(content.as_bytes())
   147→            .map_err(|e| format!("Failed to write temp file: {}", e))?;
   148→        file.sync_all()
   149→            .map_err(|e| format!("Failed to sync temp file: {}", e))?;
   150→        drop(file);
   151→
   152→        // Atomic rename
   153→        fs::rename(&temp_path, path)
   154→            .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
   155→
   156→        Ok(())
   157→    }
   158→
   159→    /// Validate the Gallops structure
   160→    ///
   161→    /// Returns Ok(()) if valid, Err(Vec<String>) with all validation errors otherwise.
   162→    pub fn jjrg_validate(&self) -> Result<(), Vec<String>> {
   163→        let mut errors = Vec::new();
   164→
   165→        // Rule 1: next_heat_seed must be 2 URL-safe base64 characters
   166→        if self.next_heat_seed.len() != 2 {
   167→            errors.push(format!(
   168→                "next_heat_seed must be 2 characters, got {}",
   169→                self.next_heat_seed.len()
   170→            ));
   171→        } else if !zjjrg_is_base64(&self.next_heat_seed) {
   172→            errors.push(format!(
   173→                "next_heat_seed contains invalid base64 characters: '{}'",
   174→                self.next_heat_seed
   175→            ));
   176→        }
   177→
   178→        // Rule 2: heats object exists (implicitly satisfied by struct)
   179→
   180→        // Validate each Heat
   181→        for (heat_key, heat) in &self.heats {
   182→            self.zjjrg_validate_heat(heat_key, heat, &mut errors);
   183→        }
   184→
   185→        if errors.is_empty() {
   186→            Ok(())
   187→        } else {
   188→            Err(errors)
   189→        }
   190→    }
   191→
   192→    fn zjjrg_validate_heat(&self, heat_key: &str, heat: &jjrg_Heat, errors: &mut Vec<String>) {
   193→        let heat_ctx = format!("Heat '{}'", heat_key);
   194→
   195→        // Rule 3: Heat key must match ₣[A-Za-z0-9_-]{2}
   196→        if !heat_key.starts_with('₣') {
   197→            errors.push(format!("{}: key must start with '₣'", heat_ctx));
   198→        } else {
   199→            let suffix = &heat_key[3..]; // ₣ is 3 bytes in UTF-8
   200→            if suffix.len() != 2 {
   201→                errors.push(format!(
   202→                    "{}: key must have 2 base64 chars after '₣', got {}",
   203→                    heat_ctx,
   204→                    suffix.len()
   205→                ));
   206→            } else if !zjjrg_is_base64(suffix) {
   207→                errors.push(format!(
   208→                    "{}: key contains invalid base64 characters",
   209→                    heat_ctx
   210→                ));
   211→            }
   212→        }
   213→
   214→        // Rule 4: Required Heat fields
   215→        // silks (non-empty kebab-case)
   216→        if !zjjrg_is_kebab_case(&heat.silks) {
   217→            errors.push(format!(
   218→                "{}: silks must be non-empty kebab-case, got '{}'",
   219→                heat_ctx, heat.silks
   220→            ));
   221→        }
   222→
   223→        // creation_time (YYMMDD)
   224→        if !zjjrg_is_yymmdd(&heat.creation_time) {
   225→            errors.push(format!(
   226→                "{}: creation_time must be YYMMDD format, got '{}'",
   227→                heat_ctx, heat.creation_time
   228→            ));
   229→        }
   230→
   231→        // status (validated by serde enum)
   232→
   233→        // next_pace_seed (3 URL-safe base64 characters)
   234→        if heat.next_pace_seed.len() != 3 {
   235→            errors.push(format!(
   236→                "{}: next_pace_seed must be 3 characters, got {}",
   237→                heat_ctx,
   238→                heat.next_pace_seed.len()
   239→            ));
   240→        } else if !zjjrg_is_base64(&heat.next_pace_seed) {
   241→            errors.push(format!(
   242→                "{}: next_pace_seed contains invalid base64 characters",
   243→                heat_ctx
   244→            ));
   245→        }
   246→
   247→        // Extract heat identity (base64 part without prefix) for pace validation
   248→        let heat_identity = if heat_key.starts_with('₣') && heat_key.len() >= 5 {
   249→            Some(&heat_key[3..]) // ₣ is 3 bytes
   250→        } else {
   251→            None
   252→        };
   253→
   254→        // Rule 5: order array and paces object must have identical key sets
   255→        let order_set: HashSet<&String> = heat.order.iter().collect();
   256→        let _paces_set: HashSet<&String> = heat.paces.keys().collect();
   257→
   258→        if order_set.len() != heat.order.len() {
   259→            errors.push(format!("{}: order array contains duplicate entries", heat_ctx));
   260→        }
   261→
   262→        let in_order_not_paces: Vec<_> = heat
   263→            .order
   264→            .iter()
   265→            .filter(|k| !heat.paces.contains_key(*k))
   266→            .collect();
   267→        let in_paces_not_order: Vec<_> = heat
   268→            .paces
   269→            .keys()
   270→            .filter(|k| !order_set.contains(k))
   271→            .collect();
   272→
   273→        if !in_order_not_paces.is_empty() {
   274→            errors.push(format!(
   275→                "{}: order contains keys not in paces: {:?}",
   276→                heat_ctx, in_order_not_paces
   277→            ));
   278→        }
   279→        if !in_paces_not_order.is_empty() {
   280→            errors.push(format!(
   281→                "{}: paces contains keys not in order: {:?}",
   282→                heat_ctx, in_paces_not_order
   283→            ));
   284→        }
   285→
   286→        // Validate each Pace
   287→        for (pace_key, pace) in &heat.paces {
   288→            self.zjjrg_validate_pace(&heat_ctx, heat_identity, pace_key, pace, errors);
   289→        }
   290→    }
   291→
   292→    fn zjjrg_validate_pace(
   293→        &self,
   294→        heat_ctx: &str,
   295→        heat_identity: Option<&str>,
   296→        pace_key: &str,
   297→        pace: &jjrg_Pace,
   298→        errors: &mut Vec<String>,
   299→    ) {
   300→        let pace_ctx = format!("{} Pace '{}'", heat_ctx, pace_key);
   301→
   302→        // Rule 6: Pace key must match ₢[A-Za-z0-9_-]{5}
   303→        if !pace_key.starts_with('₢') {
   304→            errors.push(format!("{}: key must start with '₢'", pace_ctx));
   305→        } else {
   306→            let suffix = &pace_key[3..]; // ₢ is 3 bytes in UTF-8
   307→            if suffix.len() != 5 {
   308→                errors.push(format!(
   309→                    "{}: key must have 5 base64 chars after '₢', got {}",
   310→                    pace_ctx,
   311→                    suffix.len()
   312→                ));
   313→            } else {
   314→                if !zjjrg_is_base64(suffix) {
   315→                    errors.push(format!(
   316→                        "{}: key contains invalid base64 characters",
   317→                        pace_ctx
   318→                    ));
   319→                }
   320→                // Pace must embed parent Heat identity (first 2 chars)
   321→                if let Some(heat_id) = heat_identity {
   322→                    if !suffix.starts_with(heat_id) {
   323→                        errors.push(format!(
   324→                            "{}: key must embed parent heat identity '{}', got '{}'",
   325→                            pace_ctx,
   326→                            heat_id,
   327→                            &suffix[..2.min(suffix.len())]
   328→                        ));
   329→                    }
   330→                }
   331→            }
   332→        }
   333→
   334→        // Rule 7: Pace must have silks (non-empty kebab-case)
   335→        if !zjjrg_is_kebab_case(&pace.silks) {
   336→            errors.push(format!(
   337→                "{}: silks must be non-empty kebab-case, got '{}'",
   338→                pace_ctx, pace.silks
   339→            ));
   340→        }
   341→
   342→        // Rule 7: tacks must be non-empty array
   343→        if pace.tacks.is_empty() {
   344→            errors.push(format!("{}: tacks array must not be empty", pace_ctx));
   345→        }
   346→
   347→        // Validate each Tack
   348→        for (i, tack) in pace.tacks.iter().enumerate() {
   349→            self.zjjrg_validate_tack(&pace_ctx, i, tack, errors);
   350→        }
   351→    }
   352→
   353→    fn zjjrg_validate_tack(&self, pace_ctx: &str, index: usize, tack: &jjrg_Tack, errors: &mut Vec<String>) {
   354→        let tack_ctx = format!("{} Tack[{}]", pace_ctx, index);
   355→
   356→        // Rule 8: ts must be YYMMDD-HHMM
   357→        if !zjjrg_is_yymmdd_hhmm(&tack.ts) {
   358→            errors.push(format!(
   359→                "{}: ts must be YYMMDD-HHMM format, got '{}'",
   360→                tack_ctx, tack.ts
   361→            ));
   362→        }
   363→
   364→        // Rule 8: text must be non-empty
   365→        if tack.text.is_empty() {
   366→            errors.push(format!("{}: text must not be empty", tack_ctx));
   367→        }
   368→
   369→        // Rule 9: direction presence depends on state
   370→        match tack.state {
   371→            jjrg_PaceState::Primed => {
   372→                match &tack.direction {
   373→                    None => {
   374→                        errors.push(format!(
   375→                            "{}: direction is required when state is 'primed'",
   376→                            tack_ctx
   377→                        ));
   378→                    }
   379→                    Some(d) if d.is_empty() => {
   380→                        errors.push(format!(
   381→                            "{}: direction must not be empty when state is 'primed'",
   382→                            tack_ctx
   383→                        ));
   384→                    }
   385→                    _ => {}
   386→                }
   387→            }
   388→            _ => {
   389→                if tack.direction.is_some() {
   390→                    errors.push(format!(
   391→                        "{}: direction must be absent when state is not 'primed'",
   392→                        tack_ctx
   393→                    ));
   394→                }
   395→            }
   396→        }
   397→    }
   398→}
