   400→// ===== Seed Increment Helpers =====
   401→
   402→/// Increment a base64 seed string (with carry)
   403→/// Works for both 2-char (heat) and 3-char (pace) seeds
   404→pub(crate) fn zjjrg_increment_seed(seed: &str) -> String {
   405→    let mut chars: Vec<u8> = seed.bytes().collect();
   406→    let mut carry = true;
   407→
   408→    // Process from right to left
   409→    for i in (0..chars.len()).rev() {
   410→        if !carry {
   411→            break;
   412→        }
   413→
   414→        // Find current position in charset
   415→        let pos = JJRF_CHARSET.iter().position(|&c| c == chars[i]).unwrap_or(0);
   416→
   417→        if pos == 63 {
   418→            // Wrap around
   419→            chars[i] = JJRF_CHARSET[0];
   420→            // carry remains true
   421→        } else {
   422→            chars[i] = JJRF_CHARSET[pos + 1];
   423→            carry = false;
   424→        }
   425→    }
   426→
   427→    String::from_utf8(chars).unwrap_or_else(|_| seed.to_string())
   428→}
