   534→impl jjrg_Gallops {
   535→    /// Nominate a new Heat
   536→    ///
   537→    /// Creates a new Heat with empty Pace structure and creates the paddock file.
   538→    pub fn jjrg_nominate(&mut self, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
   539→        // Validate silks is kebab-case
   540→        if !zjjrg_is_kebab_case(&args.silks) {
   541→            return Err(format!("silks must be kebab-case, got '{}'", args.silks));
   542→        }
   543→
   544→        // Validate created is YYMMDD
   545→        if !zjjrg_is_yymmdd(&args.created) {
   546→            return Err(format!("created must be YYMMDD format, got '{}'", args.created));
   547→        }
   548→
   549→        // Allocate Firemark from next_heat_seed
   550→        let firemark_str = format!("{}{}", FIREMARK_PREFIX, self.next_heat_seed);
   551→        let heat_id = self.next_heat_seed.clone();
   552→
   553→        // Compute paddock path
   554→        let paddock_file = format!(".claude/jjm/jjp_{}.md", heat_id);
   555→
   556→        // Create paddock file with template
   557→        let paddock_path = base_path.join(&paddock_file);
   558→        if let Some(parent) = paddock_path.parent() {
   559→            fs::create_dir_all(parent)
   560→                .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
   561→        }
   562→
   563→        let paddock_content = format!(
   564→            "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
   565→            args.silks
   566→        );
   567→
   568→        fs::write(&paddock_path, paddock_content)
   569→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   570→
   571→        // Create new Heat
   572→        let heat = jjrg_Heat {
   573→            silks: args.silks,
   574→            creation_time: args.created,
   575→            status: jjrg_HeatStatus::Current,
   576→            order: Vec::new(),
   577→            next_pace_seed: "AAA".to_string(),
   578→            paddock_file,
   579→            paces: BTreeMap::new(),
   580→        };
   581→
   582→        // Insert Heat
   583→        self.heats.insert(firemark_str.clone(), heat);
   584→
   585→        // Increment next_heat_seed
   586→        self.next_heat_seed = zjjrg_increment_seed(&self.next_heat_seed);
   587→
   588→        Ok(jjrg_NominateResult { firemark: firemark_str })
   589→    }
   590→
   591→    /// Slate a new Pace
   592→    ///
   593→    /// Adds a new Pace to a Heat with an initial Tack in rough state.
   594→    /// Positioning: use before/after/first to insert at specific location.
   595→    pub fn jjrg_slate(&mut self, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
   596→        // Validate silks is kebab-case
   597→        if !zjjrg_is_kebab_case(&args.silks) {
   598→            return Err(format!("silks must be kebab-case, got '{}'", args.silks));
   599→        }
   600→
   601→        // Validate text is non-empty
   602→        if args.text.is_empty() {
   603→            return Err("text must not be empty".to_string());
   604→        }
   605→
   606→        // Validate positioning mutual exclusivity
   607→        let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   608→            .iter()
   609→            .filter(|&&x| x)
   610→            .count();
   611→        if position_count > 1 {
   612→            return Err("Only one of --before, --after, or --first may be specified".to_string());
   613→        }
   614→
   615→        // Parse and normalize firemark
   616→        let firemark = Firemark::jjrf_parse(&args.firemark)
   617→            .map_err(|e| format!("Invalid firemark: {}", e))?;
   618→        let firemark_key = firemark.jjrf_display();
   619→
   620→        // Verify Heat exists
   621→        let heat = self.heats.get_mut(&firemark_key)
   622→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   623→
   624→        // If --before or --after specified, validate target coronet exists
   625→        let insert_position = if let Some(ref before_str) = args.before {
   626→            let target = Coronet::jjrf_parse(before_str)
   627→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   628→            let target_key = target.jjrf_display();
   629→            let pos = heat.order.iter().position(|c| c == &target_key)
   630→                .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   631→            Some(pos) // Insert before this position
   632→        } else if let Some(ref after_str) = args.after {
   633→            let target = Coronet::jjrf_parse(after_str)
   634→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   635→            let target_key = target.jjrf_display();
   636→            let pos = heat.order.iter().position(|c| c == &target_key)
   637→                .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   638→            Some(pos + 1) // Insert after this position
   639→        } else if args.first {
   640→            Some(0) // Insert at beginning
   641→        } else {
   642→            None // Append to end (default)
   643→        };
   644→
   645→        // Construct Coronet
   646→        let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
   647→
   648→        // Create initial Tack
   649→        let tack = jjrg_Tack {
   650→            ts: timestamp_full(),
   651→            state: jjrg_PaceState::Rough,
   652→            text: args.text,
   653→            direction: None,
   654→        };
   655→
   656→        // Create new Pace
   657→        let pace = jjrg_Pace {
   658→            silks: args.silks,
   659→            tacks: vec![tack],
   660→        };
   661→
   662→        // Insert into order at determined position
   663→        match insert_position {
   664→            Some(pos) => heat.order.insert(pos, coronet_str.clone()),
   665→            None => heat.order.push(coronet_str.clone()),
   666→        }
   667→        heat.paces.insert(coronet_str.clone(), pace);
   668→
   669→        // Increment next_pace_seed
   670→        heat.next_pace_seed = zjjrg_increment_seed(&heat.next_pace_seed);
   671→
   672→        Ok(jjrg_SlateResult { coronet: coronet_str })
   673→    }
   674→
   675→    /// Rail - reorder Paces within a Heat
   676→    ///
   677→    /// Supports two modes:
   678→    /// - Order mode: replace entire sequence with provided order array
   679→    /// - Move mode: relocate a single pace using positioning flags
   680→    pub fn jjrg_rail(&mut self, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
   681→        // Parse and normalize firemark
   682→        let firemark = Firemark::jjrf_parse(&args.firemark)
   683→            .map_err(|e| format!("Invalid firemark: {}", e))?;
   684→        let firemark_key = firemark.jjrf_display();
   685→
   686→        // Verify Heat exists
   687→        let heat = self.heats.get_mut(&firemark_key)
   688→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   689→
   690→        // Mode detection: if move_coronet present, use move mode
   691→        if let Some(ref move_str) = args.move_coronet {
   692→            // Move mode validation
   693→            if !args.order.is_empty() {
   694→                return Err("Cannot combine --move with positional coronets".to_string());
   695→            }
   696→
   697→            // Parse and normalize move coronet
   698→            let move_coronet = Coronet::jjrf_parse(move_str)
   699→                .map_err(|e| format!("Invalid --move coronet: {}", e))?;
   700→            let move_key = move_coronet.jjrf_display();
   701→
   702→            // Validate move coronet exists in heat
   703→            if !heat.paces.contains_key(&move_key) {
   704→                return Err(format!("Pace {} not found in heat {}", move_key, firemark_key));
   705→            }
   706→
   707→            // Count positioning flags
   708→            let position_count = [
   709→                args.before.is_some(),
   710→                args.after.is_some(),
   711→                args.first,
   712→                args.last,
   713→            ].iter().filter(|&&x| x).count();
   714→
   715→            if position_count == 0 {
   716→                return Err("Move mode requires exactly one positioning flag".to_string());
   717→            }
   718→            if position_count > 1 {
   719→                let mut flags = Vec::new();
   720→                if args.before.is_some() { flags.push("--before"); }
   721→                if args.after.is_some() { flags.push("--after"); }
   722→                if args.first { flags.push("--first"); }
   723→                if args.last { flags.push("--last"); }
   724→                return Err(format!("Conflicting positioning flags: {}", flags.join(", ")));
   725→            }
   726→
   727→            // Determine target position and validate
   728→            let current_pos = heat.order.iter().position(|c| c == &move_key)
   729→                .ok_or_else(|| format!("Pace {} not in order array", move_key))?;
   730→
   731→            let new_pos = if args.first {
   732→                0
   733→            } else if args.last {
   734→                heat.order.len() - 1
   735→            } else if let Some(ref before_str) = args.before {
   736→                let target = Coronet::jjrf_parse(before_str)
   737→                    .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   738→                let target_key = target.jjrf_display();
   739→
   740→                if target_key == move_key {
   741→                    return Err("Cannot position pace relative to itself".to_string());
   742→                }
   743→
   744→                let target_pos = heat.order.iter().position(|c| c == &target_key)
   745→                    .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   746→
   747→                // If moving from before target, the target shifts down after removal
   748→                if current_pos < target_pos {
   749→                    target_pos - 1
   750→                } else {
   751→                    target_pos
   752→                }
   753→            } else if let Some(ref after_str) = args.after {
   754→                let target = Coronet::jjrf_parse(after_str)
   755→                    .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   756→                let target_key = target.jjrf_display();
   757→
   758→                if target_key == move_key {
   759→                    return Err("Cannot position pace relative to itself".to_string());
   760→                }
   761→
   762→                let target_pos = heat.order.iter().position(|c| c == &target_key)
   763→                    .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   764→
   765→                // If moving from before target, the target shifts down after removal
   766→                if current_pos < target_pos {
   767→                    target_pos // After removal, target is at target_pos-1, we want target_pos-1+1 = target_pos
   768→                } else {
   769→                    target_pos + 1
   770→                }
   771→            } else {
   772→                unreachable!()
   773→            };
   774→
   775→            // Remove from current position and insert at new position
   776→            heat.order.remove(current_pos);
   777→            heat.order.insert(new_pos, move_key);
   778→
   779→        } else {
   780→            // Order mode: replace entire sequence
   781→
   782→            // Normalize the input order (add prefix if missing)
   783→            let normalized_order: Result<Vec<String>, String> = args.order.iter()
   784→                .map(|c| {
   785→                    let coronet = Coronet::jjrf_parse(c)
   786→                        .map_err(|e| format!("Invalid coronet '{}': {}", c, e))?;
   787→                    Ok(coronet.jjrf_display())
   788→                })
   789→                .collect();
   790→            let new_order = normalized_order?;
   791→
   792→            // Validate count matches
   793→            if new_order.len() != heat.order.len() {
   794→                return Err(format!(
   795→                    "Order count mismatch: got {}, expected {}",
   796→                    new_order.len(),
   797→                    heat.order.len()
   798→                ));
   799→            }
   800→
   801→            // Validate no duplicates
   802→            let new_set: HashSet<&String> = new_order.iter().collect();
   803→            if new_set.len() != new_order.len() {
   804→                return Err("Order contains duplicate Coronets".to_string());
   805→            }
   806→
   807→            // Validate all Coronets exist in paces
   808→            for coronet in &new_order {
   809→                if !heat.paces.contains_key(coronet) {
   810→                    return Err(format!("Coronet '{}' not found in Heat's paces", coronet));
   811→                }
   812→            }
   813→
   814→            // Validate all Coronets embed correct parent Firemark
   815→            for coronet in &new_order {
   816→                let c = Coronet::jjrf_parse(coronet).unwrap();
   817→                if c.jjrf_parent_firemark().jjrf_display() != firemark_key {
   818→                    return Err(format!(
   819→                        "Coronet '{}' does not embed parent Heat '{}'",
   820→                        coronet, firemark_key
   821→                    ));
   822→                }
   823→            }
   824→
   825→            // Replace order
   826→            heat.order = new_order;
   827→        }
   828→
   829→        // Return the new order
   830→        Ok(heat.order.clone())
   831→    }
   832→
   833→    /// Tally - add a new Tack to a Pace
   834→    ///
   835→    /// Prepends a new Tack with state transition and/or plan refinement.
   836→    pub fn jjrg_tally(&mut self, args: jjrg_TallyArgs) -> Result<(), String> {
   837→        // Parse and normalize coronet
   838→        let coronet = Coronet::jjrf_parse(&args.coronet)
   839→            .map_err(|e| format!("Invalid coronet: {}", e))?;
   840→        let coronet_key = coronet.jjrf_display();
   841→
   842→        // Extract parent Firemark
   843→        let firemark = coronet.jjrf_parent_firemark();
   844→        let firemark_key = firemark.jjrf_display();
   845→
   846→        // Verify Heat exists
   847→        let heat = self.heats.get_mut(&firemark_key)
   848→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   849→
   850→        // Verify Pace exists
   851→        let pace = heat.paces.get_mut(&coronet_key)
   852→            .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
   853→
   854→        // Read current Tack
   855→        let current_tack = pace.tacks.first()
   856→            .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
   857→
   858→        // Determine new state
   859→        let new_state = args.state.clone().unwrap_or_else(|| current_tack.state.clone());
   860→
   861→        // Determine new direction
   862→        let new_direction = match (&args.state, &new_state) {
   863→            // State explicitly set to primed: direction required
   864→            (Some(jjrg_PaceState::Primed), _) => {
   865→                match &args.direction {
   866→                    Some(d) if !d.is_empty() => Some(d.clone()),
   867→                    Some(_) => return Err("direction must not be empty when state is primed".to_string()),
   868→                    None => return Err("direction is required when state is primed".to_string()),
   869→                }
   870→            }
   871→            // State explicitly set to something other than primed: direction forbidden
   872→            (Some(_), _) => {
   873→                if args.direction.is_some() {
   874→                    return Err("direction must be absent when state is not primed".to_string());
   875→                }
   876→                None
   877→            }
   878→            // State inherited and was primed: inherit direction
   879→            (None, jjrg_PaceState::Primed) => {
   880→                args.direction.or_else(|| current_tack.direction.clone())
   881→            }
   882→            // State inherited and was not primed: no direction
   883→            (None, _) => None,
   884→        };
   885→
   886→        // Determine new text
   887→        let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
   888→        if new_text.is_empty() {
   889→            return Err("text must not be empty".to_string());
   890→        }
   891→
   892→        // Create new Tack
   893→        let new_tack = jjrg_Tack {
   894→            ts: timestamp_full(),
   895→            state: new_state,
   896→            text: new_text,
   897→            direction: new_direction,
   898→        };
   899→
   900→        // Prepend to tacks array
   901→        pace.tacks.insert(0, new_tack);
   902→
   903→        Ok(())
   904→    }
   905→
   906→    /// Draft - move a Pace from one Heat to another
   907→    ///
   908→    /// Moves the pace to the destination heat with a new Coronet.
   909→    /// All Tack history is preserved, with a new Tack recording the draft.
   910→    /// State is NOT changed - draft is a move operation, not a state transition.
   911→    pub fn jjrg_draft(&mut self, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
   912→        // Validate positioning mutual exclusivity
   913→        let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   914→            .iter()
   915→            .filter(|&&x| x)
   916→            .count();
   917→        if position_count > 1 {
   918→            return Err("Only one of --before, --after, or --first may be specified".to_string());
   919→        }
   920→
   921→        // Parse and normalize source coronet
   922→        let source_coronet = Coronet::jjrf_parse(&args.coronet)
   923→            .map_err(|e| format!("Invalid coronet: {}", e))?;
   924→        let source_coronet_key = source_coronet.jjrf_display();
   925→
   926→        // Extract source Firemark from coronet
   927→        let source_firemark = source_coronet.jjrf_parent_firemark();
   928→        let source_firemark_key = source_firemark.jjrf_display();
   929→
   930→        // Parse and normalize destination firemark
   931→        let dest_firemark = Firemark::jjrf_parse(&args.to)
   932→            .map_err(|e| format!("Invalid destination firemark: {}", e))?;
   933→        let dest_firemark_key = dest_firemark.jjrf_display();
   934→
   935→        // Validate source and destination are different
   936→        if source_firemark_key == dest_firemark_key {
   937→            return Err("Cannot draft pace to same heat".to_string());
   938→        }
   939→
   940→        // Verify source heat exists
   941→        if !self.heats.contains_key(&source_firemark_key) {
   942→            return Err(format!("Source heat '{}' not found", source_firemark_key));
   943→        }
   944→
   945→        // Verify destination heat exists
   946→        if !self.heats.contains_key(&dest_firemark_key) {
   947→            return Err(format!("Heat '{}' not found", dest_firemark_key));
   948→        }
   949→
   950→        // Verify pace exists in source heat
   951→        {
   952→            let source_heat = self.heats.get(&source_firemark_key).unwrap();
   953→            if !source_heat.paces.contains_key(&source_coronet_key) {
   954→                return Err(format!("Pace {} not found in heat {}", source_coronet_key, source_firemark_key));
   955→            }
   956→        }
   957→
   958→        // Validate positioning target if specified
   959→        let insert_position = if let Some(ref before_str) = args.before {
   960→            let target = Coronet::jjrf_parse(before_str)
   961→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   962→            let target_key = target.jjrf_display();
   963→            let dest_heat = self.heats.get(&dest_firemark_key).unwrap();
   964→            let pos = dest_heat.order.iter().position(|c| c == &target_key)
   965→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   966→            Some(pos)
   967→        } else if let Some(ref after_str) = args.after {
   968→            let target = Coronet::jjrf_parse(after_str)
   969→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   970→            let target_key = target.jjrf_display();
   971→            let dest_heat = self.heats.get(&dest_firemark_key).unwrap();
   972→            let pos = dest_heat.order.iter().position(|c| c == &target_key)
   973→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   974→            Some(pos + 1)
   975→        } else if args.first {
   976→            Some(0)
   977→        } else {
   978→            None // Append to end
   979→        };
   980→
   981→        // Remove pace from source heat
   982→        let source_heat = self.heats.get_mut(&source_firemark_key).unwrap();
   983→        let pace_data = source_heat.paces.remove(&source_coronet_key)
   984→            .ok_or_else(|| format!("Pace {} not found", source_coronet_key))?;
   985→        source_heat.order.retain(|c| c != &source_coronet_key);
   986→
   987→        // Get destination heat and allocate new coronet
   988→        let dest_heat = self.heats.get_mut(&dest_firemark_key).unwrap();
   989→        let new_coronet_str = format!("{}{}{}", CORONET_PREFIX, dest_firemark.jjrf_as_str(), dest_heat.next_pace_seed);
   990→
   991→        // Create new tack recording the draft
   992→        let draft_note = format!("Drafted from {} in {}.\n\n{}",
   993→            source_coronet_key, source_firemark_key,
   994→            pace_data.tacks.first().map(|t| t.text.as_str()).unwrap_or(""));
   995→
   996→        let draft_tack = jjrg_Tack {
   997→            ts: timestamp_full(),
   998→            state: pace_data.tacks.first().map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough),
   999→            text: draft_note,
  1000→            direction: pace_data.tacks.first().and_then(|t| t.direction.clone()),
  1001→        };
  1002→
  1003→        // Build new pace with draft tack prepended
  1004→        let mut new_tacks = vec![draft_tack];
  1005→        new_tacks.extend(pace_data.tacks);
  1006→
  1007→        let new_pace = jjrg_Pace {
  1008→            silks: pace_data.silks,
  1009→            tacks: new_tacks,
  1010→        };
  1011→
  1012→        // Insert into destination heat
  1013→        match insert_position {
  1014→            Some(pos) => dest_heat.order.insert(pos, new_coronet_str.clone()),
  1015→            None => dest_heat.order.push(new_coronet_str.clone()),
  1016→        }
  1017→        dest_heat.paces.insert(new_coronet_str.clone(), new_pace);
  1018→
  1019→        // Increment destination seed
  1020→        dest_heat.next_pace_seed = zjjrg_increment_seed(&dest_heat.next_pace_seed);
  1021→
  1022→        Ok(jjrg_DraftResult { new_coronet: new_coronet_str })
  1023→    }
  1024→
  1025→    /// Retire a Heat
  1026→    ///
  1027→    /// Creates trophy file, removes heat from gallops, deletes paddock file.
  1028→    /// Does NOT save gallops or commit - caller is responsible for that.
  1029→    pub fn jjrg_retire(
  1030→        &mut self,
  1031→        args: jjrg_RetireArgs,
  1032→        base_path: &Path,
  1033→        steeplechase: &[SteeplechaseEntry],
  1034→    ) -> Result<jjrg_RetireResult, String> {
  1035→        // Parse and normalize firemark
  1036→        let firemark = Firemark::jjrf_parse(&args.firemark)
  1037→            .map_err(|e| format!("Invalid firemark: {}", e))?;
  1038→        let firemark_key = firemark.jjrf_display();
  1039→
  1040→        // Validate today is YYMMDD
  1041→        if !zjjrg_is_yymmdd(&args.today) {
  1042→            return Err(format!("today must be YYMMDD format, got '{}'", args.today));
  1043→        }
  1044→
  1045→        // Verify heat exists
  1046→        let heat = self.heats.get(&firemark_key)
  1047→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
  1048→
  1049→        // Read paddock content before we remove anything
  1050→        let paddock_path = base_path.join(&heat.paddock_file);
  1051→        let paddock_content = fs::read_to_string(&paddock_path)
  1052→            .map_err(|e| format!("Failed to read paddock file '{}': {}", heat.paddock_file, e))?;
  1053→
  1054→        // Build trophy content
  1055→        let trophy_content = self.zjjrg_build_trophy_content(&firemark_key, heat, &paddock_content, &args.today, steeplechase)?;
  1056→
  1057→        // Compute trophy path: .claude/jjm/retired/jjh_<created>-r<today>-<silks>.md
  1058→        let trophy_filename = format!(
  1059→            "jjh_{}-r{}-{}.md",
  1060→            heat.creation_time,
  1061→            args.today,
  1062→            heat.silks
  1063→        );
  1064→        let trophy_rel_path = format!(".claude/jjm/retired/{}", trophy_filename);
  1065→        let trophy_full_path = base_path.join(&trophy_rel_path);
  1066→
  1067→        // Create retired directory if needed
  1068→        if let Some(parent) = trophy_full_path.parent() {
  1069→            fs::create_dir_all(parent)
  1070→                .map_err(|e| format!("Failed to create retired directory: {}", e))?;
  1071→        }
  1072→
  1073→        // Write trophy file
  1074→        fs::write(&trophy_full_path, trophy_content)
  1075→            .map_err(|e| format!("Failed to write trophy file: {}", e))?;
  1076→
  1077→        // Capture info for result before removing heat
  1078→        let silks = heat.silks.clone();
  1079→        let paddock_file = heat.paddock_file.clone();
  1080→
  1081→        // Remove heat from gallops (do NOT change next_heat_seed)
  1082→        self.heats.remove(&firemark_key);
  1083→
  1084→        // Delete paddock file
  1085→        if paddock_path.exists() {
  1086→            fs::remove_file(&paddock_path)
  1087→                .map_err(|e| format!("Failed to delete paddock file: {}", e))?;
  1088→        }
  1089→
  1090→        Ok(jjrg_RetireResult {
  1091→            trophy_path: trophy_rel_path,
  1092→            paddock_path: paddock_file,
  1093→            silks,
  1094→            firemark: firemark_key,
  1095→        })
  1096→    }
  1097→
  1098→    /// Build trophy markdown preview (dry-run, no file modifications)
  1099→    ///
  1100→    /// Returns the markdown content that would be written to the trophy file.
  1101→    pub fn jjrg_build_trophy_preview(
  1102→        &self,
  1103→        firemark: &str,
  1104→        paddock_content: &str,
  1105→        today: &str,
  1106→        steeplechase: &[SteeplechaseEntry],
  1107→    ) -> Result<String, String> {
  1108→        // Parse and normalize firemark
  1109→        let fm = Firemark::jjrf_parse(firemark)
  1110→            .map_err(|e| format!("Invalid firemark: {}", e))?;
  1111→        let firemark_key = fm.jjrf_display();
  1112→
  1113→        // Verify heat exists
  1114→        let heat = self.heats.get(&firemark_key)
  1115→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
  1116→
  1117→        self.zjjrg_build_trophy_content(&firemark_key, heat, paddock_content, today, steeplechase)
  1118→    }
  1119→
  1120→    /// Build trophy markdown content
  1121→    fn zjjrg_build_trophy_content(
  1122→        &self,
  1123→        firemark_key: &str,
  1124→        heat: &jjrg_Heat,
  1125→        paddock_content: &str,
  1126→        today: &str,
  1127→        steeplechase: &[SteeplechaseEntry],
  1128→    ) -> Result<String, String> {
  1129→        let mut content = String::new();
  1130→
  1131→        // Header
  1132→        content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
  1133→        content.push_str(&format!("**Firemark:** {}\n", firemark_key));
  1134→        content.push_str(&format!("**Created:** {}\n", heat.creation_time));
  1135→        content.push_str(&format!("**Retired:** {}\n", today));
  1136→        content.push_str("**Status:** retired\n\n");
  1137→
  1138→        // Paddock
  1139→        content.push_str("## Paddock\n\n");
  1140→        content.push_str(paddock_content);
  1141→        if !paddock_content.ends_with('\n') {
  1142→            content.push('\n');
  1143→        }
  1144→        content.push('\n');
  1145→
  1146→        // Paces (in order)
  1147→        content.push_str("## Paces\n\n");
  1148→        for coronet_key in &heat.order {
  1149→            if let Some(pace) = heat.paces.get(coronet_key) {
  1150→                // Get final state from most recent tack
  1151→                let final_state = pace.tacks.first()
  1152→                    .map(|t| match t.state {
  1153→                        jjrg_PaceState::Rough => "rough",
  1154→                        jjrg_PaceState::Primed => "primed",
  1155→                        jjrg_PaceState::Complete => "complete",
  1156→                        jjrg_PaceState::Abandoned => "abandoned",
  1157→                    })
  1158→                    .unwrap_or("unknown");
  1159→
  1160→                content.push_str(&format!(
  1161→                    "### {} ({}) [{}]\n\n",
  1162→                    pace.silks, coronet_key, final_state
  1163→                ));
  1164→
  1165→                // Tack history (newest first, as stored)
  1166→                for tack in &pace.tacks {
  1167→                    let state_str = match tack.state {
  1168→                        jjrg_PaceState::Rough => "rough",
  1169→                        jjrg_PaceState::Primed => "primed",
  1170→                        jjrg_PaceState::Complete => "complete",
  1171→                        jjrg_PaceState::Abandoned => "abandoned",
  1172→                    };
  1173→                    content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
  1174→                    content.push_str(&tack.text);
  1175→                    if !tack.text.ends_with('\n') {
  1176→                        content.push('\n');
  1177→                    }
  1178→                    if let Some(ref direction) = tack.direction {
  1179→                        content.push_str(&format!("\n*Direction:* {}\n", direction));
  1180→                    }
  1181→                    content.push('\n');
  1182→                }
  1183→            }
  1184→        }
  1185→
  1186→        // Steeplechase (newest first, as provided)
  1187→        content.push_str("## Steeplechase\n\n");
  1188→        if steeplechase.is_empty() {
  1189→            content.push_str("(no entries)\n\n");
  1190→        } else {
  1191→            for entry in steeplechase {
  1192→                // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
  1193→                let identity = entry.coronet.as_deref().unwrap_or("Heat");
  1194→                let action = entry.action.as_deref().unwrap_or("notch");
  1195→                content.push_str(&format!(
  1196→                    "### {} - {} - {}\n\n",
  1197→                    entry.timestamp, identity, action
  1198→                ));
  1199→                content.push_str(&entry.subject);
  1200→                if !entry.subject.ends_with('\n') {
  1201→                    content.push('\n');
  1202→                }
  1203→                content.push('\n');
  1204→            }
  1205→        }
  1206→
  1207→        Ok(content)
  1208→    }
  1209→}
  1210→
  1211→/// Read text from stdin (for CLI commands)
  1212→pub fn jjrg_read_stdin() -> Result<String, String> {
  1213→    let mut buffer = String::new();
  1214→    std::io::stdin().read_to_string(&mut buffer)
  1215→        .map_err(|e| format!("Failed to read from stdin: {}", e))?;
  1216→    Ok(buffer.trim_end().to_string())
  1217→}
  1218→
  1219→/// Read text from stdin, returning None if stdin is empty or a tty
  1220→pub fn jjrg_read_stdin_optional() -> Result<Option<String>, String> {
  1221→    use std::io::IsTerminal;
  1222→
  1223→    // If stdin is a terminal, no input was piped
  1224→    if std::io::stdin().is_terminal() {
  1225→        return Ok(None);
  1226→    }
  1227→
  1228→    let text = jjrg_read_stdin()?;
  1229→    if text.is_empty() {
  1230→        Ok(None)
  1231→    } else {
  1232→        Ok(Some(text))
  1233→    }
  1234→}
