use super::jjrg_gallops::*;
use std::collections::BTreeMap;

#[test]
fn jjtg_pace_state_serialization() {
    let state = jjrg_PaceState::Rough;
    let json = serde_json::to_string(&state).unwrap();
    assert_eq!(json, "\"rough\"");
